import ipaddress
import socket
from urllib.parse import urlparse
import requests
from flask import Flask, request, jsonify

app = Flask(__name__)

# Blocked IP ranges
BLOCKED_IP_RANGES = [
    ipaddress.ip_network('0.0.0.0/8'),          # Current network
    ipaddress.ip_network('10.0.0.0/8'),         # Private
    ipaddress.ip_network('127.0.0.0/8'),        # Loopback
    ipaddress.ip_network('169.254.0.0/16'),     # Link-local (metadata)
    ipaddress.ip_network('172.16.0.0/12'),      # Private
    ipaddress.ip_network('192.168.0.0/16'),     # Private
    ipaddress.ip_network('224.0.0.0/4'),        # Multicast
    ipaddress.ip_network('240.0.0.0/4'),        # Reserved
    ipaddress.ip_network('::1/128'),            # IPv6 loopback
    ipaddress.ip_network('fe80::/10'),          # IPv6 link-local
    ipaddress.ip_network('fc00::/7'),           # IPv6 private
]

# Blocked hostnames
BLOCKED_HOSTNAMES = [
    'metadata.google.internal',
    'metadata',
    'localhost',
    '169.254.169.254',
]

# Allowed protocols
ALLOWED_PROTOCOLS = ['http', 'https']

# Domain allowlist (example - configure for your use case)
ALLOWED_DOMAINS = [
    'api.example.com',
    'cdn.example.com',
    'trusted-partner.com'
]

class SSRFException(Exception):
    pass

def is_ip_blocked(ip_str):
    """Check if IP address is in blocked ranges."""
    try:
        ip = ipaddress.ip_address(ip_str)
        for blocked_range in BLOCKED_IP_RANGES:
            if ip in blocked_range:
                return True
        return False
    except ValueError:
        return True  # Invalid IP format

def validate_url(url, use_allowlist=True):
    """
    Validate URL to prevent SSRF attacks.

    Args:
        url: User-supplied URL
        use_allowlist: If True, only allow domains in ALLOWED_DOMAINS

    Returns:
        Validated URL

    Raises:
        SSRFException: If URL is invalid or blocked
    """
    try:
        # Parse URL
        parsed = urlparse(url)

        # Validate protocol
        if parsed.scheme not in ALLOWED_PROTOCOLS:
            raise SSRFException(
                f"Protocol '{parsed.scheme}' not allowed. "
                f"Only {ALLOWED_PROTOCOLS} are permitted."
            )

        # Validate hostname exists
        if not parsed.hostname:
            raise SSRFException("Invalid URL: hostname missing")

        # Check blocked hostnames
        hostname_lower = parsed.hostname.lower()
        for blocked in BLOCKED_HOSTNAMES:
            if blocked in hostname_lower:
                raise SSRFException(
                    f"Access to '{parsed.hostname}' is not permitted"
                )

        # Resolve hostname to IP
        try:
            ip_addresses = socket.getaddrinfo(
                parsed.hostname, 
                parsed.port or 80,
                family=socket.AF_UNSPEC,
                type=socket.SOCK_STREAM
            )
        except socket.gaierror:
            raise SSRFException(
                f"Unable to resolve hostname: {parsed.hostname}"
            )

        # Check all resolved IPs
        for ip_info in ip_addresses:
            ip_addr = ip_info[4][0]
            if is_ip_blocked(ip_addr):
                raise SSRFException(
                    f"Access to IP address {ip_addr} is not permitted"
                )

        # Domain allowlist check
        if use_allowlist:
            domain_allowed = any(
                parsed.hostname == domain or 
                parsed.hostname.endswith('.' + domain)
                for domain in ALLOWED_DOMAINS
            )
            if not domain_allowed:
                raise SSRFException(
                    f"Domain '{parsed.hostname}' is not in allowlist"
                )

        return url

    except SSRFException:
        raise
    except Exception as e:
        raise SSRFException(f"URL validation error: {str(e)}")

def safe_fetch_url(url, timeout=5, max_redirects=3):
    """
    Safely fetch URL with SSRF protection.
    """
    try:
        # Initial validation
        validated_url = validate_url(url, use_allowlist=True)

        # Configure session with security settings
        session = requests.Session()
        session.max_redirects = max_redirects

        # Custom redirect handler to validate each redirect
        class SSRFAdapter(requests.adapters.HTTPAdapter):
            def send(self, request, **kwargs):
                # Validate URL after redirects
                try:
                    validate_url(request.url, use_allowlist=False)
                except SSRFException as e:
                    raise requests.exceptions.RequestException(
                        f"Redirect blocked: {str(e)}"
                    )
                return super().send(request, **kwargs)

        session.mount('http://', SSRFAdapter())
        session.mount('https://', SSRFAdapter())

        # Make request
        response = session.get(
            validated_url,
            timeout=timeout,
            allow_redirects=True,
            headers={'User-Agent': 'SecureApp/1.0'}
        )

        return response

    except SSRFException as e:
        raise
    except requests.exceptions.RequestException as e:
        raise SSRFException(f"Request failed: {str(e)}")

@app.route('/api/fetch', methods=['POST'])
def fetch_url():
    """API endpoint to fetch external URLs."""
    try:
        data = request.get_json()
        url = data.get('url')

        if not url:
            return jsonify({'error': 'URL parameter required'}), 400

        # Fetch URL with SSRF protection
        response = safe_fetch_url(url)

        return jsonify({
            'status': 'success',
            'status_code': response.status_code,
            'content_length': len(response.content),
            'content_type': response.headers.get('Content-Type')
        })

    except SSRFException as e:
        return jsonify({
            'error': 'SSRF protection',
            'message': str(e)
        }), 403
    except Exception as e:
        return jsonify({
            'error': 'Request failed'
        }), 500

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)

