const express = require('express');
const axios = require('axios');
const { URL } = require('url');
const dns = require('dns').promises;
const ipaddr = require('ipaddr.js');

const app = express();
app.use(express.json());

// Blocked IP ranges (RFC 1918, link-local, etc.)
const BLOCKED_RANGES = [
  { start: '0.0.0.0', end: '0.255.255.255' },
  { start: '10.0.0.0', end: '10.255.255.255' },
  { start: '127.0.0.0', end: '127.255.255.255' },
  { start: '169.254.0.0', end: '169.254.255.255' },
  { start: '172.16.0.0', end: '172.31.255.255' },
  { start: '192.168.0.0', end: '192.168.255.255' },
  { start: '224.0.0.0', end: '239.255.255.255' },
  { start: '240.0.0.0', end: '255.255.255.255' },
];

const BLOCKED_HOSTNAMES = [
  'metadata.google.internal',
  'metadata',
  'localhost',
  '169.254.169.254',
];

const ALLOWED_PROTOCOLS = ['http:', 'https:'];

const ALLOWED_DOMAINS = [
  'api.example.com',
  'cdn.example.com',
  'trusted-partner.com'
];

function isIPBlocked(ip) {
  try {
    const addr = ipaddr.parse(ip);

    // Check for loopback
    if (addr.range() === 'loopback') return true;

    // Check for link-local
    if (addr.range() === 'linkLocal') return true;

    // Check for private
    if (addr.range() === 'private') return true;

    // Check IPv4 ranges
    if (addr.kind() === 'ipv4') {
      const bytes = addr.toByteArray();
      const ipNum = (bytes[0] << 24) | (bytes[1] << 16) | 
                    (bytes[2] << 8) | bytes[3];

      for (const range of BLOCKED_RANGES) {
        const startBytes = ipaddr.parse(range.start).toByteArray();
        const endBytes = ipaddr.parse(range.end).toByteArray();
        const startNum = (startBytes[0] << 24) | (startBytes[1] << 16) |
                        (startBytes[2] << 8) | startBytes[3];
        const endNum = (endBytes[0] << 24) | (endBytes[1] << 16) |
                      (endBytes[2] << 8) | endBytes[3];

        if (ipNum >= startNum && ipNum <= endNum) {
          return true;
        }
      }
    }

    return false;
  } catch (e) {
    return true; // Invalid IP format
  }
}

async function validateURL(urlString, useAllowlist = true) {
  try {
    const url = new URL(urlString);

    // Validate protocol
    if (!ALLOWED_PROTOCOLS.includes(url.protocol)) {
      throw new Error(
        `Protocol '${url.protocol}' not allowed. ` +
        `Only ${ALLOWED_PROTOCOLS.join(', ')} are permitted.`
      );
    }

    // Check blocked hostnames
    const hostname = url.hostname.toLowerCase();
    for (const blocked of BLOCKED_HOSTNAMES) {
      if (hostname.includes(blocked)) {
        throw new Error(`Access to '${url.hostname}' is not permitted`);
      }
    }

    // Resolve DNS
    let addresses;
    try {
      addresses = await dns.resolve4(url.hostname);
    } catch (dnsError) {
      throw new Error(`Unable to resolve hostname: ${url.hostname}`);
    }

    // Check all resolved IPs
    for (const ip of addresses) {
      if (isIPBlocked(ip)) {
        throw new Error(
          `Access to IP address ${ip} is not permitted`
        );
      }
    }

    // Domain allowlist check
    if (useAllowlist) {
      const domainAllowed = ALLOWED_DOMAINS.some(domain => 
        hostname === domain || hostname.endsWith('.' + domain)
      );

      if (!domainAllowed) {
        throw new Error(
          `Domain '${url.hostname}' is not in allowlist`
        );
      }
    }

    return urlString;

  } catch (error) {
    throw new Error(`URL validation failed: ${error.message}`);
  }
}

async function safeFetchURL(url, timeout = 5000, maxRedirects = 3) {
  try {
    // Initial validation
    await validateURL(url, true);

    // Configure axios with security settings
    const response = await axios.get(url, {
      timeout,
      maxRedirects,
      validateStatus: (status) => status < 400,
      headers: {
        'User-Agent': 'SecureApp/1.0'
      },
      // Validate redirects
      beforeRedirect: async (options) => {
        try {
          await validateURL(options.url, false);
        } catch (e) {
          throw new Error(`Redirect blocked: ${e.message}`);
        }
      }
    });

    return response;

  } catch (error) {
    throw new Error(`Request failed: ${error.message}`);
  }
}

app.post('/api/fetch', async (req, res) => {
  try {
    const { url } = req.body;

    if (!url) {
      return res.status(400).json({ error: 'URL parameter required' });
    }

    // Fetch URL with SSRF protection
    const response = await safeFetchURL(url);

    res.json({
      status: 'success',
      statusCode: response.status,
      contentLength: response.data.length,
      contentType: response.headers['content-type']
    });

  } catch (error) {
    console.error('SSRF protection:', error.message);
    res.status(403).json({
      error: 'SSRF protection',
      message: 'Request blocked for security reasons'
    });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

# Terraform configuration for EC2 with IMDSv2 enforced

resource "aws_instance" "web_server" {
  ami           = "ami-0c55b159cbfafe1f0"
  instance_type = "t3.medium"

  # Enforce IMDSv2
  metadata_options {
    http_endpoint               = "enabled"
    http_tokens                 = "required"  # Require IMDSv2
    http_put_response_hop_limit = 1
    instance_metadata_tags      = "enabled"
  }

  # Attach IAM role with least privilege
  iam_instance_profile = aws_iam_instance_profile.app_profile.name

  # Security group with egress filtering
  vpc_security_group_ids = [aws_security_group.app_sg.id]

  tags = {
    Name        = "web-server-ssrf-protected"
    Environment = "production"
  }
}

# Security group blocking metadata endpoint access
resource "aws_security_group" "app_sg" {
  name        = "app-security-group"
  description = "Application security group with SSRF protection"
  vpc_id      = aws_vpc.main.id

  # Allow outbound HTTPS to internet
  egress {
    description = "HTTPS to internet"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow outbound HTTP to internet
  egress {
    description = "HTTP to internet"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Block access to metadata endpoint (defense in depth)
  # Note: This is redundant with IMDSv2 but provides additional protection
  egress {
    description = "Block metadata endpoint"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["169.254.169.254/32"]
    self        = false
  }

  tags = {
    Name = "app-sg-ssrf-protected"
  }
}

# IAM role with least privilege
resource "aws_iam_role" "app_role" {
  name = "app-instance-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Restrictive IAM policy - only allow specific actions
resource "aws_iam_role_policy" "app_policy" {
  name = "app-policy"
  role = aws_iam_role.app_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "arn:aws:s3:::app-bucket-name/allowed-prefix/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:*:*:log-group:/aws/ec2/app:*"
        ]
      }
    ]
  })
}

resource "aws_iam_instance_profile" "app_profile" {
  name = "app-instance-profile"
  role = aws_iam_role.app_role.name
}
